object TranslationHelper {

    private val trToEnDictionary: Map<String, String> = buildMap {
        putAll(TranslationHelperPart1.dict)
        putAll(TranslationHelperPart2.dict)
        putAll(TranslationHelperPart3.dict)
        putAll(TranslationHelperPart4.dict)
        putAll(TranslationHelperPart5.dict)
        putAll(TranslationHelperPart6.dict)
        putAll(TranslationHelperPart7.dict)
        putAll(TranslationHelperPart8.dict)
        putAll(TranslationHelperPart9.dict)
        putAll(TranslationHelperPart10.dict)
        putAll(TranslationHelperPart11.dict)
        putAll(TranslationHelperPart12.dict)
    }

    fun translate(text: String, currentLanguage: String): String {
        if (currentLanguage == "tr") return text
        
        // Return matched key directly from the dictionary
        trToEnDictionary[text]?.let { return it }

        // Clean trailing spaces and try again
        val trimmed = text.trim()
        trToEnDictionary[trimmed]?.let { return it }

        // Bullet list item check
        if (trimmed.startsWith("• ")) {
            val key = trimmed.removePrefix("• ").trim()
            trToEnDictionary[key]?.let { return "• $it" }
        }

        return text
    }

    fun translateDoseKey(key: String, currentLanguage: String): String {
        if (currentLanguage == "tr") {
            return if (key.lowercase(Locale.ROOT) == "dozaj") "Dozaj" else key.replace("_", " ").replaceFirstChar { if (it.isLowerCase()) it.titlecase(Locale.ROOT) else it.toString() }
        }
        return when (key.lowercase(Locale.ROOT)) {
            "dozaj" -> "Dosing"
            "acil_reversal" -> "Emergency Reversal"
            "akut_hipokalsemi" -> "Acute Hypocalcemia"
            "anafilaksi" -> "Anaphylaxis"
            "analjezi" -> "Analgesia"
