            "bradikardi" -> "Bradycardia"
            "bronkospazm" -> "Bronchospasm"
            "bronkospazm_akut" -> "Acute Bronchospasm"
            "bronkospazm_direncli" -> "Resistant Bronchospasm"
            "derin_reversal" -> "Deep Reversal"
            "dosing" -> "Dosing"
            "entubasyon" -> "Intubation"
            "epidural" -> "Epidural"
